```solidity
pragma solidity ^0.8.12;

contract SecureNFTMintingAndDistribution {
    enum State { MintingPreparation, MintingActive, Distribution }
    State public currentState = State.MintingPreparation;

    address public owner;
    uint256 public totalSupply;
    uint256 public maxSupply;
    uint256 public price;
    uint256 public currentBatchMinted;
    uint256[] public teamPercentages;
    address[] public receiverAddresses;
    mapping(address => uint256) public balances;

    event Minted(address indexed to, uint256 tokenId);
    event FundsDistributed();

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    modifier nonReentrant() {
        require(_reentrancyGuard == 0, "Reentrancy guard");
        _reentrancyGuard = 1;
        _;
        _reentrancyGuard = 0;
    }

    uint256 private _reentrancyGuard;

    constructor(uint256 _maxSupply, uint256 _price, uint256[] memory _teamPercentages, address[] memory _receiverAddresses) {
        owner = msg.sender;
        maxSupply = _maxSupply;
        price = _price;
        teamPercentages = _teamPercentages;
        receiverAddresses = _receiverAddresses;
    }

    function startMinting() external onlyOwner {
        require(currentState == State.MintingPreparation, "Minting already started");
        currentState = State.MintingActive;
    }

    function mint() external payable nonReentrant {
        require(currentState == State.MintingActive, "Minting not active");
        require(totalSupply + 1 <= maxSupply, "Max supply reached");
        require(msg.value >= price, "Insufficient payment");

        totalSupply++;
        currentBatchMinted++;
        emit Minted(msg.sender, totalSupply);
    }

    function distributeFunds() external onlyOwner nonReentrant {
        require(currentState == State.MintingActive, "Minting not active");
        require(currentBatchMinted >= maxSupply, "Minting not complete");

        uint256 balance = address(this).balance;
        uint256 totalAmount = 0;

        for (uint256 i = 0; i < receiverAddresses.length; i++) {
            uint256 amount = (balance * teamPercentages[i]) / 1000;
            totalAmount += amount;
            balances[receiverAddresses[i]] += amount;
        }

        currentState = State.Distribution;
        emit FundsDistributed();
    }

    function sendFunds(address payable recipient, uint256 amount) external onlyOwner nonReentrant {
        require(currentState == State.Distribution, "Funds not ready for distribution");
        require(balances[recipient] >= amount, "Insufficient balance");

        balances[recipient] -= amount;
        (bool sent,) = recipient.call{value: amount}("");
        require(sent, "Failed to send Ether");
    }

    function withdrawTeamMemberBalanceTo(address payable recipient) external nonReentrant {
        require(currentState == State.Distribution, "Funds not ready for distribution");
        uint256 amount = balances[msg.sender];
        require(amount > 0, "No balance to withdraw");

        balances[msg.sender] = 0;
        (bool sent,) = recipient.call{value: amount}("");
        require(sent, "Failed to send Ether");
    }

    receive() external payable {}
}
```

